app.openapi(authGeneralRoutes.signOut, async (ctx) => {
  const confirmMfa = await getAuthCookie(ctx, 'confirm-mfa');

  if (confirmMfa) {
    // Delete mfa cookie
    deleteAuthCookie(ctx, 'confirm-mfa');

    logEvent(ctx, 'info', 'User mfa canceled');

    return ctx.body(null, 204);
  }

  // Find session & invalidate
  const { sessionToken } = await getParsedSessionCookie(ctx, { deleteOnError: true, deleteAfterAttempt: true });
  const { session: currentSession } = await validateSession(sessionToken);

  await deleteSession(ctx, { sessionId: currentSession.id, userId: currentSession.userId });

  invalidateCache.user(currentSession.userId);
  logEvent(ctx, 'info', 'User signed out', { userId: currentSession.userId });

  return ctx.body(null, 204);
});

const validateSession = async (
  hashedSessionToken: string,
): Promise<{ session: SessionModel; user: UserWithCounters }> => {
  const [result] = await db
    .select({ session: sessionsTable, user: userSelect })
    .from(sessionsTable)
    .where(eq(sessionsTable.secret, hashedSessionToken))
    .innerJoin(usersTable, eq(sessionsTable.userId, usersTable.id));

  // If no result is found throw no session
  if (!result) throw new AppError(401, 'no_session', 'warn');

  const { session, user } = result;

  // Check if the session has expired and invalidate it if so
  if (isExpiredDate(session.expiresAt)) throw new AppError(401, 'session_expired', 'warn');

  // Strip secret from session before returning
  const { secret: _, ...safeSession } = session;
  return { session: safeSession, user };
};

const findNewsletterRecipients = async (
  ctx: DbContext,
  { organizationIds, roles }: FindNewsletterRecipientsOpts,
) => {
  const { db } = ctx.var;
  return db
    .selectDistinct({
      email: usersTable.email,
      name: usersTable.name,
      unsubscribeToken: unsubscribeTokensTable.secret,
      newsletter: usersTable.newsletter,
      orgName: organizationsTable.name,
    })
    .from(membershipsTable)
    .innerJoin(usersTable, eq(usersTable.id, membershipsTable.userId))
    .innerJoin(unsubscribeTokensTable, eq(usersTable.id, unsubscribeTokensTable.userId))
    .innerJoin(organizationsTable, eq(organizationsTable.id, membershipsTable.organizationId))
    .where(
      and(
        eq(membershipsTable.contextType, 'organization'),
        inArray(membershipsTable.organizationId, organizationIds),
        inArray(membershipsTable.role, roles),
        eq(usersTable.newsletter, true),
      ),
    );
};

const getValidContextEntity = async <T extends ContextEntityType>(
  ctx: AuthContext,
  entityId: string,
  entityType: T,
  action: Exclude<EntityActionType, 'create'>,
  bySlug = false,
): Promise<ValidContextEntityResult<T>> => {
  // Get current user role and memberships from request context
  const isSystemAdmin = ctx.var.isSystemAdmin;
  const memberships = ctx.var.memberships;

  // Step 1: Resolve target entity by ID (or slug when bySlug is true)
  const entity = await resolveEntity(ctx, entityType, entityId, bySlug);
  if (!entity) throw new AppError(404, 'not_found', 'warn', { entityType });

  // Step 2: Check permission for the requested action (system admin bypass is handled inside)
  const { isAllowed, membership } = checkPermission(memberships, action, entity, { isSystemAdmin });

  if (!isAllowed) {
    throw new AppError(403, 'forbidden', 'warn', { entityType, meta: { action } });
  }

  return { entity, membership };
};
